import express from 'express';
import { Autumn } from 'autumn-js';

const router = express.Router();

// Initialize Autumn SDK with secret key from environment
const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY
});

/**
 * POST /billing/preview-upgrade
 * Preview a plan upgrade before confirming
 */
router.post('/preview-upgrade', async (req, res) => {
  const { customerId, targetPlanId } = req.body;

  // Validate required fields
  if (!customerId || !targetPlanId) {
    return res.status(400).json({
      error: 'customerId and targetPlanId are required'
    });
  }

  try {
    const preview = await autumn.billing.previewAttach({
      customerId,
      planId: targetPlanId
    });

    return res.status(200).json(preview);
  } catch (err) {
    return res.status(502).json({
      error: 'Billing service unavailable',
      details: err.message
    });
  }
});

/**
 * POST /billing/confirm-upgrade
 * Confirm and execute a plan upgrade
 */
router.post('/confirm-upgrade', async (req, res) => {
  const { customerId, targetPlanId, confirmed } = req.body;

  // Validate required fields
  if (!customerId || !targetPlanId || confirmed === undefined) {
    return res.status(400).json({
      error: 'customerId, targetPlanId, and confirmed are required'
    });
  }

  // If not confirmed, return cancelled status
  if (confirmed === false) {
    return res.status(200).json({
      status: 'cancelled'
    });
  }

  try {
    const result = await autumn.billing.attach({
      customerId,
      planId: targetPlanId
    });

    return res.status(200).json({
      status: 'upgraded',
      customerId,
